import './index.css';

import LoginForm from
'../../components/forms/LoginForm';

function LoginPage() {

  return (

    <div className="login-page">

      <div className="login-left">

        <h1>
          Student Academic
          Performance &
          Evaluation System
        </h1>

        <p>
          Manage student marks,
          analytics, reports,
          and academic progress.
        </p>

      </div>

      <div className="login-right">

        <LoginForm />

      </div>

    </div>

  );

}

export default LoginPage;
